+      continue;
+    }
+    const normalized = raw.replace(/^b\//, '').replace(/^\.\//, '').trim();
+    if (!normalized || normalized === '/dev/null') {
+      continue;
+    }
+    paths.add(normalized);
+  }
+  return Array.from(paths);
